class Solution {
public:
    int canBeTypedWords(string text, string brokenLetters) {
        bool broken[26] = {false};
        for (char c : brokenLetters) broken[c - 'a'] = true;

        int res = 0, i = 0, n = text.size();
        while (i < n) {
            bool ok = true;
            while (i < n && text[i] != ' ') {
                if (broken[text[i] - 'a']) ok = false;
                ++i;
            }
            res += ok;
            ++i;
        }
        return res;
    }
};
```
